 const _20250115LHistoireDanne = "{\"parsed\":{\"_path\":\"/fr/20250115-l-histoire-danne\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Anne, le faux Brad Pitt et un véritable lynchage numérique\",\"description\":\"L'histoire tragique d'Anne, victime d'une arnaque en ligne par un faux Brad Pitt qui lui a extorqué 800 000 euros, suivie d'un lynchage médiatique sur les réseaux sociaux. Une réflexion sur la cruauté numérique et le respect de la dignité humaine.\",\"image\":\"/images/articles/anne.jpg\",\"createdAt\":\"2025-01-15\",\"id\":\"2025-01-15T00:00:00.000Z\",\"keywords\":\"arnaque en ligne, faux Brad Pitt, escroquerie amoureuse, lynchage numérique, cyberharcèlement, arnaque romance, brouteur, extorsion de fonds, réseaux sociaux, Twitter, X\",\"summary\":\"Anne, une femme fragilisée par un cancer du cerveau, le VIH et un divorce, est tombée dans le piège d'escrocs se faisant passer pour Brad Pitt. Après avoir perdu 830 000 euros et tenté de se suicider, elle subit désormais un lynchage médiatique sur les réseaux sociaux. Cet article appelle au respect de la dignité humaine face à la cruauté numérique.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"anne-le-faux-brad-pitt-et-un-véritable-lynchage-numérique\"},\"children\":[{\"type\":\"text\",\"value\":\"Anne, le faux Brad Pitt et un véritable lynchage numérique\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Préambule : cette sombre histoire trouve ses racines dans mon pays d'origine, le Bénin. Aux dernières nouvelles, les autorités compétentes ont été informées de cette affaire, les escrocs responsables ayant été identifiées par Find My Scammer. Ils iront donc probablement faire un long séjour en prison, et la justice sera rendue, car ces individus ne représentent en rien les valeurs traditionnelles de respect,de dignité humaine et d'hospitalité propres au Bénin.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En d'autres termes, on peut en parler avec la paix du coeur, sans exploiter le désarroi et le désespoir des victimes.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mon usage des réseaux sociaux est limité. Je me concentre principalement sur YouTube, que j'écoute en arrière-plan pendant mes activités, et sur quelques comptes destinés à relayer le contenu de mes blogs.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"... (contenu abrégé)\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20250115-l-histoire-danne.md\",\"_source\":\"content\",\"_file\":\"fr/20250115-l-histoire-danne.md\",\"_stem\":\"fr/20250115-l-histoire-danne\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20250115-l-histoire-danne\"}},\"hash\":\"JxagGkWmKQ\"}";

